function scorriChatInBasso(){if($(".chat_message_bubble_user").length>0){var position=$(".chat_message_bubble_user").last().position();$('html, body').animate({scrollTop:position.top},500)}}
function aggiornaChat(){$.ajaxQueue({url:baseUrl+"/virtual-assistant/messages/",cache:!1,async:!0,dataType:"html",success:function(content){$(".chat_messages").html(content);setTimeout(function(){scorriChatInBasso()},100)}})}
function initAssistenteVirtualeWidget(){var widget=$(".assistente_virtuale_widget");if(!widget.length)
return;var body=$("body");var toggle=widget.find(".assistente_virtuale_widget_toggle");var close=widget.find(".assistente_virtuale_widget_close");var overlay=widget.find(".assistente_virtuale_widget_overlay");var panel=widget.find(".assistente_virtuale_widget_panel");var iframe=widget.find(".assistente_virtuale_widget_iframe");var chatUrl=widget.data("chat-url");function caricaIframe(){if(!iframe.attr("src")&&chatUrl)
iframe.attr("src",chatUrl);}
function impostaStato(aperto){widget.toggleClass("assistente_virtuale_widget_open",aperto);body.toggleClass("assistente_virtuale_widget_opened",aperto);toggle.attr("aria-expanded",aperto?"true":"false");panel.attr("aria-hidden",aperto?"false":"true");if(aperto)
caricaIframe();}
toggle.on("click",function(){impostaStato(!widget.hasClass("assistente_virtuale_widget_open"))});close.on("click",function(){impostaStato(!1)});overlay.on("click",function(){impostaStato(!1)});$(document).on("keydown",function(e){if(e.key==="Escape"&&widget.hasClass("assistente_virtuale_widget_open"))
impostaStato(!1);})}
$(document).ready(function(){scorriChatInBasso();initAssistenteVirtualeWidget();$("body").on("keypress",".request_message",function(e){if(e.which==13){e.preventDefault();$(".send_request_to_va").trigger("click")}});$("body").on("click",".send_request_to_va",function(e){e.preventDefault();var bottone=$(this);var loader=bottone.find(".send_request_to_va_loader");var testo=bottone.find(".send_request_to_va_text");var messaggio=$(".request_message").val();if(!messaggio.length||bottone.prop("disabled"))
return;bottone.prop("disabled",!0);testo.addClass("uk-hidden");loader.removeClass("uk-hidden");$.ajaxQueue({url:baseUrl+"/virtual-assistant/request/",async:!0,cache:!1,type:"POST",data:{messaggio:messaggio},dataType:"html",success:function(content){$(".request_message").val("");aggiornaChat()},complete:function(){bottone.prop("disabled",!1);testo.removeClass("uk-hidden");loader.addClass("uk-hidden")}})})})